        .init(id: "rcp.interior.scandiliving", studio: "interior", title: "Scandi Living Room (daylight)", subjectExample: "a beautifully styled Scandinavian living room with a light oak sofa, a linen throw and cushions, a low coffee table on a soft wool rug, a leafy potted plant, framed art and styled shelves, warm and inviting magazine interior design", chipIDs: ["env.scandi", "light.window", "angle.onepoint", "lens.24mm", "color.warm"], note: "Bright airy Scandinavian living room, one-point view with verticals tending to stay parallel — that's a bias, not a guarantee, and the same room from another angle won't match.", badge: .green, featured: true),
