        .init(id: "rcp.food.overheadflatlay", studio: "food", title: "Overhead Flat Lay", subjectExample: "a bowl of fresh garden salad with cherry tomatoes", chipIDs: ["obj.flatlay", "angle.over", "env.wood", "light.window", "color.vibrant"], note: "Top-down flat lay on a rustic table with fresh, vibrant color — great for spreads and recipe shots; arrange your own props, the model won't add legible labels.", badge: .green, featured: true),
