        .init(id: "rcp.food.darkmoody", studio: "food", title: "Dark & Moody", subjectExample: "a seared steak with roasted vegetables on a dark plate", chipIDs: ["style.editorial", "light.lowkey", "env.slatesurface", "lens.macro100", "color.muted"], note: "Dark, moody restaurant mood with deep shadows and rich detail — dramatic and premium; works best on a single dish, not a crowded table.", badge: .green, featured: false),
        .init(id: "rcp.food.brightfresh", studio: "food", title: "Bright & Fresh", subjectExample: "a stack of pancakes with berries and maple syrup", chipIDs: ["style.commercial", "light.softbox", "env.linenbackdrop", "color.warm", "lens.deep"], note: "Bright, airy, everything-in-focus styling on a light backdrop — clean and fresh for breakfast and bakery shots.", badge: .green, featured: true),
