        .init(id: "rcp.food.finedining", studio: "food", title: "Fine-Dining Plate", subjectExample: "a plated scallop dish with a glossy butter sauce pooled under the scallops", chipIDs: ["style.product", "frame.centered", "env.marble", "light.softbox", "color.muted"], note: "Centered fine-dining plate on a marble surface, restrained and elegant. 🟡 Centered composition is fragile on a single dish — the plate may sit off-axis — and delicate sauce drizzle may under-render; describe the sauce concretely.", badge: .green, featured: false),
        .init(id: "rcp.auto.studiohero", studio: "auto", title: "Studio Hero", subjectExample: "a sleek silver electric sedan", chipIDs: ["style.automotive", "env.studio", "light.threepoint", "angle.threequarter", "lens.medformat", "color.cool"], note: "Glossy paint with crisp studio reflections on a clean seamless backdrop — the classic catalogue hero shot. 🟡 Keep the badge/logo area generic; Klein invents fake brand marks if you ask for a real one.", badge: .green, featured: true),
