        .init(id: "rcp.industry.workerppe", studio: "industry", title: "Worker in PPE (portrait)", subjectExample: "a man in his 40s in a hard hat, safety glasses and hi-vis jacket", chipIDs: ["expr.serious", "style.documentary", "env.factoryfloor", "light.window", "frame.half", "lens.85mm"], note: "Flattering documentary half-body portrait with soft side light; faces are good but not flawless and any helmet/jacket logo will render as junk — keep it plain.", badge: .green, featured: true),
        .init(id: "rcp.industry.warehouseaisle", studio: "industry", title: "Warehouse Aisle", subjectExample: "a worker pushing a pallet jack down a tall racking aisle", chipIDs: ["pose.walking", "style.documentary", "env.warehouseaisle", "light.practical", "angle.onepoint", "lens.24mm"], note: "Strong one-point-perspective aisle receding into depth with practical ceiling light; rack labels, barcodes and box text will be illegible — leave them blurred.", badge: .green, featured: false),
        .init(id: "rcp.industry.fleetdawn", studio: "industry", title: "Truck Fleet at Dawn", subjectExample: "a row of semi-trucks parked in a logistics yard", chipIDs: ["style.automotive", "env.logisticsyard", "light.golden", "angle.low", "lens.anamorphic", "color.tealorange"], note: "Cinematic dawn fleet shot with glossy reflections and a wide anamorphic feel; use generic trailers — real brand logos and any plate/door text hallucinate.", badge: .yellow, featured: false),
        .init(id: "rcp.industry.cleanlab", studio: "industry", title: "Clean Lab", subjectExample: "a technician in a white coat and gloves at a lab bench", chipIDs: ["expr.neutral", "style.commercial", "env.minimalist", "light.singlesoft", "frame.half", "color.coldsteel"], note: "Clean, bright lab/process look with soft even light and a cool grade. No true lab environment exists, so it renders a clean minimal room around the technician; instrument displays and reagent labels won't read — keep numbers and screens out of focus.", badge: .yellow, featured: false),
        .init(id: "rcp.jewelry.ringfacets", studio: "jewelry", title: "Ring: Gem Facets", subjectExample: "a solitaire diamond ring with a faceted gemstone", chipIDs: ["lens.macro100", "frame.xclose", "env.slatesurface", "light.spotlight", "color.coldsteel"], note: "Razor-sharp facet sparkle and tiny specular highlights pooled out of the dark slate. 9B recommended for the crispest facets. Keep any engraved band blank — Klein garbles tiny text.", badge: .green, featured: true),
        .init(id: "rcp.jewelry.goldchainsilk", studio: "jewelry", title: "Gold Chain on Silk", subjectExample: "a single fine gold chain necklace gently coiled in one continuous draped line on fabric", chipIDs: ["obj.flatlay", "lens.macro", "env.linenbackdrop", "light.window", "color.warm"], note: "Warm gold links catching soft window light on draped linen — luxe flat-lay feel. Clasp shape is approximate, not an engineered render. (Backdrop is linen, not silk.)", badge: .green, featured: true),
        .init(id: "rcp.jewelry.watchdial", studio: "jewelry", title: "Watch Dial (macro)", subjectExample: "a luxury wristwatch with a metallic dial, a plain clean face with only simple hour markers and no text, and a polished case", chipIDs: ["lens.macro100", "frame.insert", "env.brushedmetal", "style.product"], note: "🟡 Gorgeous dial texture, hands and reflections, but any numerals/markers or logo come out as garbled pseudo-text — frame it as a believable hero image, not a real-brand watch.", badge: .yellow, featured: false),
        .init(id: "rcp.jewelry.dewycream", studio: "jewelry", title: "Cream: Dewy Texture", subjectExample: "a swirl of moisturizer cream with a glossy dewy surface", chipIDs: ["lens.macro100", "frame.xclose", "light.singlesoft", "env.concretesurface", "color.softmatte"], note: "Dewy, glistening cream texture with soft droplet highlights — pure surface macro, no jar/label needed so nothing to garble.", badge: .green, featured: true),
        .init(id: "rcp.jewelry.lipstickhero", studio: "jewelry", title: "Lipstick Hero", subjectExample: "an open lipstick bullet in a glossy tube", chipIDs: ["obj.pedestal", "frame.insert", "light.spotlight", "light.rim", "env.greybackdrop"], note: "Crisp angled bullet with a rim-lit edge on a clean backdrop. 🟡 The tight spot can render as a visible light beam rather than just a pool of light. Leave the tube blank — printed brand text comes out as junk lettering.", badge: .green, featured: false),
        .init(id: "rcp.jewelry.perfumecaustics", studio: "jewelry", title: "Perfume Bottle: Caustics", subjectExample: "a faceted glass perfume bottle with amber liquid", chipIDs: ["obj.pedestal", "lens.macro", "light.hazeback", "env.marble", "color.warm"], note: "🟡 Beautiful glass caustics, light refraction and warm liquid glow on marble. Keep the bottle label-free — Klein invents fake logo/text on any printed surface.", badge: .yellow, featured: false),
        .init(id: "rcp.sport.sprinter", studio: "sport", title: "Sprinter mid-stride", subjectExample: "a lone track sprinter driving out of the blocks mid-stride, plain unmarked racing kit", chipIDs: ["pose.midaction", "lens.freezeaction", "frame.full", "angle.low", "light.hardsun", "color.tealorange"], note: "Keep the kit and shoes generic — any jersey number or sponsor logo will render as garbled marks.", badge: .green, featured: true),
        .init(id: "rcp.sport.cyclist-pan", studio: "sport", title: "Cyclist panning blur", subjectExample: "a road cyclist leaning into a bend at speed, body sharp against a streaked motion-blurred background", chipIDs: ["pose.midaction", "lens.panblur", "frame.wide", "light.golden", "style.cinematic"], note: "Panning sells speed by blurring the background; the rider's bib and gear stay generic — no legible text.", badge: .green, featured: true),
        .init(id: "rcp.sport.climber", studio: "sport", title: "Climber on the wall", subjectExample: "a solo climber reaching for a hold high on a sheer rock face, one arm extended, fingers gripping", chipIDs: ["pose.midaction", "angle.hero", "frame.full", "env.coastalcliffs", "light.rim", "lens.tele135"], note: "Hold the frame to one climber and avoid extreme finger close-ups — small grips and hands can distort.", badge: .green, featured: true),
        .init(id: "rcp.sport.swimmer", studio: "sport", title: "Swimmer in the lane", subjectExample: "a freestyle swimmer pulling through the water mid-stroke, arm breaking the surface with spray", chipIDs: ["pose.midaction", "lens.freezeaction", "env.poollane", "frame.half", "color.coldsteel"], note: "Frozen water spray reads well but individual droplets and splash edges can soften — keep it one swimmer.", badge: .green, featured: false),
        .init(id: "rcp.sport.boxer", studio: "sport", title: "Boxer in the ring", subjectExample: "a single boxer in a boxing ring throwing a punch, gloves up, body torqued", chipIDs: ["pose.midaction", "light.lowkey", "light.spotlight", "frame.cowboy", "color.bleachbypass"], note: "One fighter only — a second figure or tight glove-and-hand detail tends to degrade. The dark moody ring is carried by the pooled spotlight, not a gym background.", badge: .green, featured: false),
        .init(id: "rcp.sport.yoga-sunrise", studio: "sport", title: "Yoga at sunrise", subjectExample: "a person standing calmly in a yoga pose on a quiet hillside at first light, hands pressed together at the chest, eyes closed", chipIDs: ["env.meadow", "light.golden", "frame.full", "lens.85mm", "color.warm"], note: "Single figure with ONE clear arm position - that is what stops the extra-arm glitch (two conflicting arm cues, a tall reaching pose plus arms extended, used to render four arms). Even so, hands and limbs are never guaranteed on the 4-step model: regenerate if a limb looks off. Keep clothing plain so no text appears.", badge: .yellow, featured: false),
        .init(id: "rcp.abstract.gradientmesh", studio: "abstract", title: "Gradient mesh wash", subjectExample: "a deep teal-to-magenta gradient mesh with soft blended color transitions", chipIDs: ["env.gradientmesh", "color.vibrant", "frame.negspace"], note: "A clean text-free background image — add your headline or logo in Canva or Figma.", badge: .green, featured: true),
        .init(id: "rcp.abstract.fluidink", studio: "abstract", title: "Flowing fluid ink", subjectExample: "swirling indigo and gold ink blooming through water in slow drifting tendrils", chipIDs: ["env.fluidink", "color.cool", "lens.macro", "light.window"], note: "A clean text-free background image — add your headline or logo in Canva or Figma.", badge: .green, featured: true),
        .init(id: "rcp.abstract.softbokeh", studio: "abstract", title: "Soft bokeh lights", subjectExample: "a field of warm out-of-focus light orbs glowing against a dark blurred backdrop", chipIDs: ["env.bokehlights", "lens.85mm", "color.warm", "frame.negspace", "light.lowkey"], note: "A clean text-free background image — add your headline or logo in Canva or Figma.", badge: .green, featured: true),
        .init(id: "rcp.abstract.smokehaze", studio: "abstract", title: "Drifting smoke haze", subjectExample: "soft curling wisps of pale smoke drifting across a dark muted background", chipIDs: ["env.smokehaze", "color.muted", "light.rim", "frame.negspace"], note: "A clean text-free background image — add your headline or logo in Canva or Figma.", badge: .green, featured: false),
        .init(id: "rcp.abstract.materialmacro", studio: "abstract", title: "Macro material texture", subjectExample: "an extreme close-up of veined white marble with subtle grey striations", chipIDs: ["env.materialmacro", "lens.macro100", "color.muted"], note: "A clean text-free background image — add your headline or logo in Canva or Figma.", badge: .green, featured: false),
        .init(id: "rcp.abstract.lightstreaks", studio: "abstract", title: "Sweeping light streaks", subjectExample: "long flowing streaks of coloured light sweeping diagonally across a dark frame", chipIDs: ["env.lightstreaks", "color.tealorange", "light.neon", "frame.negspace"], note: "A clean text-free background image — add your headline or logo in Canva or Figma.", badge: .green, featured: false),
        .init(id: "rcp.abstract.geometric3d", studio: "abstract", title: "3D geometric shapes", subjectExample: "softly lit floating pastel cubes and spheres arranged across a clean studio void", chipIDs: ["env.geometric3d", "style.render3d", "color.pastel", "light.softbox", "frame.negspace"], note: "A clean text-free background with a CGI render look — shapes only, not real geometry or assets; add your headline or logo in Canva or Figma.", badge: .yellow, featured: false),
        .init(id: "rcp.blackwhite.streetcandid", studio: "blackwhite", title: "Street Candid (B/W)", subjectExample: "a black-and-white monochrome documentary street photograph, no color, an older man in a flat cap crossing a wet city street, mid-stride", chipIDs: ["pose.walking", "style.documentary", "color.bw", "env.street", "light.overcast", "lens.film35"], note: "Black-and-white street photograph. 🟡 The B/W grade can lose to strong color cues and render in muted color — if so, regenerate. Single subject reads best; a passer-by or two may smear and faces are good-not-flawless.", badge: .yellow, featured: true),
        .init(id: "rcp.blackwhite.fineartportrait", studio: "blackwhite", title: "Fine-Art Portrait (high-contrast)", subjectExample: "a woman with windswept short hair, half her face turned into shadow", chipIDs: ["expr.serious", "style.cinematic", "color.bw", "light.chiaroscuro", "frame.closeup", "lens.85mm"], note: "Deep shadow can swallow fine detail; faces look strong but not retouch-flawless.", badge: .green, featured: true),
        .init(id: "rcp.blackwhite.moodyarchitecture", studio: "blackwhite", title: "Moody Architecture (B/W)", subjectExample: "a brutalist concrete stairwell with a single shaft of light falling across the steps", chipIDs: ["style.documentary", "color.bw", "env.industrial", "light.hardsingle", "angle.low", "lens.24mm"], note: "Repeating tiny windows or rails may bend slightly; no legible signage or numbers.", badge: .green, featured: true),
        .init(id: "rcp.blackwhite.landscape", studio: "blackwhite", title: "B/W Landscape", subjectExample: "a lone tree on a windswept moor under a heavy bank of storm clouds", chipIDs: ["style.cinematic", "color.bw", "env.foggymoor", "light.overcast", "frame.wide", "lens.largeformat"], note: "Far-distance texture softens; sky-vs-land tonal split is the whole picture, keep it spacious.", badge: .green, featured: false),
        .init(id: "rcp.blackwhite.reportage", studio: "blackwhite", title: "Documentary Reportage", subjectExample: "a market vendor leaning over a crate of produce, caught mid-gesture", chipIDs: ["pose.handlingobject", "style.documentary", "color.bw", "env.street", "light.window", "lens.50mm"], note: "Hands mid-gesture and any background crowd degrade; keep the action to one clear figure.", badge: .green, featured: false),
    ]

    static let redPanel: [RedPanelRow] = [
        .init(trap: "Legible text in the image", who: "Poster / flyer / menu designers, marketers, thumbnail makers, social-media creators", fails: "Posters, flyers, menus, ad copy, captions, subtitles, video-thumbnail text and any words longer than a word or two come out misspelled, garbled or invented — and the 4-step model is worse at it than slower models. Reserved 'empty space for your headline' is a bias, not a guarantee.", reframe: "Generate the artwork, backdrop or scene here, then drop the real text on top in Canva, Figma, Keynote, Photoshop or Pages — where it stays sharp and you can edit it."),
        .init(trap: "App icons, UI mockups, vector & transparent assets", who: "App / web designers, brand & product teams, anyone needing an SVG or a transparent PNG", fails: "No real vector (SVG) output, no built-in transparency or cut-out, no pixel-exact buttons / toolbars / screens. You get a flat raster painting of an interface, not a usable icon or editable layout — sizes and pixels won't line up.", reframe: "Use it for moodboards, hero imagery and 'what could this look like' concepts, then build the actual icon or UI in Figma / Sketch / Illustrator. For a cut-out, remove the background afterward in a dedicated tool."),
        .init(trap: "Real 3D files, CAD & dimensioned drawings", who: "Product / industrial designers, architects, engineers, 3D artists, makers", fails: "It only paints a 2D picture that looks 3D. No .obj / .stl / STEP file, no CAD geometry, no measured floor plans, no dimensioned or to-scale technical drawings — nothing you can print, mill or rotate. There's also no turnaround: each angle is a different, inconsistent object.", reframe: "Great for early concept art and 'mood' renders to show a direction. For anything buildable, model it in Blender / Fusion 360 / SketchUp / a CAD tool, where measurements are real."),
        .init(trap: "Charts, maps, gauges, readable numbers & code", who: "Analysts, data / BI teams, finance, dashboard & infographic designers, developers", fails: "Graphs, diagrams, maps, dashboards, dials, tables, prices, phone numbers, code on a screen — the numbers and labels are fake and the geometry doesn't add up. It paints something chart-shaped, not your data.", reframe: "Use it for the decorative frame or background only. Make the actual chart in Excel / Sheets / a BI tool, the map in a maps service, and screenshot real code — then composite if you want the styled look."),
        .init(trap: "Exact brand logos & trademarks", who: "Brand designers, agencies, anyone placing a company logo", fails: "It can't reproduce a real logo accurately — it hallucinates a junk pseudo-logo, even on a surface you asked to keep blank (a 'plain' bottle, sign or jersey). Wordmarks come out as garbled lettering.", reframe: "Generate the product, packaging or scene with a clean, empty surface, then place the official logo file yourself in an editor — that's also the only way to stay on-brand and avoid trademark trouble."),
        .init(trap: "The same character, product or room across images", who: "Comic / storyboard artists, brand & product photographers, game & film pre-viz", fails: "Every render is independent — no consistent character, mascot, product or set across a series, and no 360° turnaround. Faces are good but not flawless, and crowds and hands degrade on 4 steps (it leans toward a single, small subject).", reframe: "Use it for one-off hero shots and concept frames. For a consistent cast or product line, train or use a LoRA, lean on flattering light and lens for faces, and keep the scene to one or two subjects."),
        .init(trap: "Medical & diagnostic imagery", who: "Clinicians, medical educators, health publishers, patients", fails: "A realistic-looking X-ray, scan, skin photo, lab result or anatomy figure is invented — confidently wrong details that could be mistaken for a real diagnosis. We ship no medical preset because a believable fake here is dangerous, not helpful.", reframe: "For teaching or illustration, use licensed medical atlases and real, consented clinical images. Never present a generated image as a real scan or as medical evidence."),
        .init(trap: "News, events & 'real' photos of real people", who: "Journalists, editors, fact-checkers, PR, social-media managers", fails: "It can paint a photoreal 'news photo' of an event that never happened or a public figure doing something they didn't — and it looks real enough to deceive. There's no provenance and no studio preset for this, on purpose.", reframe: "Use real, sourced photography for anything presented as news or as a real event. If you make an illustration, label it clearly as an illustration / AI-generated so no one mistakes it for a record of fact."),
        .init(trap: "Police, forensic & surveillance use", who: "Law enforcement, investigators, legal, security teams", fails: "No reliable face match, no 'enhance' of a blurry photo into a real identity, no evidence-grade reconstruction. It invents plausible-looking detail that isn't in the source — which can implicate the wrong person. We provide no studio for this.", reframe: "Treat generated images as never admissible and never identifying. Use validated forensic tools and chain-of-custody evidence for anything that affects a real person's case."),
        .init(trap: "Anything you need exact and repeatable", who: "Print production, spec / handoff, QA, regulated industries", fails: "It won't hit an exact color value, exact dimensions, exact placement, a specific font, or the same result on demand from a vague prompt. Tiny details drift between renders.", reframe: "Let it generate the look and the variations, then lock the exact specs (color, size, type, layout) in a real design / print tool. Save the seed and recipe if you want to get close to a render again."),
    ]
}

enum StudioPriority: String, Sendable { case top, high, med }

struct LibraryStudio: Identifiable, Hashable, Sendable {
    let id: String
    let title: String
    let badge: PresetBadge
    let icon: String
    let priority: StudioPriority
}

struct SceneRecipe: Identifiable, Hashable, Sendable {
    let id: String
    let studio: String
    let title: String
    let subjectExample: String
    let chipIDs: [String]
    let note: String
    let badge: PresetBadge
    let featured: Bool
}

struct RedPanelRow: Identifiable, Hashable, Sendable {
    var id: String { trap }
    let trap: String
    let who: String
    let fails: String
    let reframe: String
}
